 1	import { ResourceLink, useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 2	import {
 3	  FormGroup,
 4	  FormHelperText,
 5	  FormSelect,
 6	  FormSelectOption,
 7	  HelperText,
 8	  HelperTextItem,
 9	} from '@patternfly/react-core';
10	import * as React from 'react';
11	import { HTTPRoute } from './types'; // You will need to define this type similarly to Gateway.
12	import { useTranslation } from 'react-i18next';
13	
14	interface HTTPRouteSelectProps {
15	  selectedHTTPRoute: HTTPRoute;
16	  onChange: (updated: HTTPRoute) => void;
17	}
18	
19	const HTTPRouteSelect: React.FC<HTTPRouteSelectProps> = ({ selectedHTTPRoute, onChange }) => {
20	  const { t } = useTranslation('plugin__kuadrant-console-plugin');
21	  const [httpRoutes, setHTTPRoutes] = React.useState([]);
22	  const gvk = { group: 'gateway.networking.k8s.io', version: 'v1', kind: 'HTTPRoute' };
23	
24	  const httpRouteResource = {
25	    groupVersionKind: gvk,
26	    isList: true,
27	  };
28	
29	  const [httpRouteData, httpRouteLoaded, httpRouteError] = useK8sWatchResource(httpRouteResource);
30	
31	  React.useEffect(() => {
32	    if (httpRouteLoaded && !httpRouteError && Array.isArray(httpRouteData)) {
33	      setHTTPRoutes(
34	        httpRouteData.map((httpRoute) => ({
35	          name: httpRoute.metadata.name,
36	          namespace: httpRoute.metadata.namespace,
37	        })),
38	      );
39	    }
40	  }, [httpRouteData, httpRouteLoaded, httpRouteError]);
41	
42	  const handleHTTPRouteChange = (event: React.FormEvent<HTMLSelectElement>) => {
43	    const [namespace, name] = event.currentTarget.value.split('/');
44	    onChange({ ...selectedHTTPRoute, name, namespace });
45	  };
46	
47	  return (
48	    <>
49	      <FormGroup label={t('HTTPRoute API Target Reference')} isRequired fieldId="httproute-select">
50	        <FormSelect
51	          id="httproute-select"
52	          value={`${selectedHTTPRoute.namespace}/${selectedHTTPRoute.name}`}
53	          onChange={handleHTTPRouteChange}
54	          aria-label={t('Select HTTPRoute')}
55	        >
56	          <FormSelectOption
57	            key="placeholder"
58	            value=""
59	            label={t('Select an HTTPRoute')}
60	            isPlaceholder
61	          />
62	          {httpRoutes.map((httpRoute, index) => (
63	            <FormSelectOption
64	              key={index}
65	              value={`${httpRoute.namespace}/${httpRoute.name}`}
66	              label={`${httpRoute.namespace}/${httpRoute.name}`}
67	            />
68	          ))}
69	        </FormSelect>
70	        <FormHelperText>
71	          <HelperText>
72	            <HelperTextItem>
73	              {t('You can view and create HTTPRoutes')}{' '}
74	              <ResourceLink
75	                groupVersionKind={gvk}
76	                title="Create an HTTPRoute"
77	                hideIcon={true}
78	                inline={true}
79	                displayName="here"
80	              />
81	            </HelperTextItem>
82	          </HelperText>
83	        </FormHelperText>
84	      </FormGroup>
85	    </>
86	  );
87	};
88	
89	export default HTTPRouteSelect;

